const REPO_STATS_TTL_MS=864e5;function getCachedRepoStats(t){try{let e=localStorage.getItem(`repo-stats-${t}`);if(!e)return null;let n=JSON.parse(e);if(Date.now()-n.timestamp>864e5)return localStorage.removeItem(`repo-stats-${t}`),null;return n.data}catch(a){return null}}function cacheRepoStats(t,e){try{let n={timestamp:Date.now(),data:e};localStorage.setItem(`repo-stats-${t}`,JSON.stringify(n))}catch(a){}}function updateRepoStatsDOM(t,e){document.getElementById(`watch-${e}`).innerHTML=` ${t.watchers_count}`,document.getElementById(`star-${e}`).innerHTML=` ${t.stargazers_count}`,document.getElementById(`fork-${e}`).innerHTML=` ${t.forks_count}`,document.getElementById(`caption-${e}`).innerHTML=` ${t.description}`}function setRepoStats(t,e){let n=getCachedRepoStats(t);if(n){updateRepoStatsDOM(n,e);return}let a=`https://api.github.com/repos/inviro/${t}`;fetch(a,{method:"GET",headers:{Accept:"application/json","Content-Type":"application/json","User-Agent":"AbrahamChen.com"}}).then(t=>t.json()).then(n=>{cacheRepoStats(t,n),updateRepoStatsDOM(n,e)}).catch(()=>{})}function loadProject(t){let e=document.getElementById(t),n=e.firstElementChild.innerHTML,a=t.split("-")[1],r=`<a href = 'https://github.com/inviro/${n}'>${n}</a>`;e.firstElementChild.innerHTML=r,r=`<a href="https://github.com/inviro/${n}/watchers" aria-label = "${n} Watchers"><i class="fa fa-lg fa-eye" id="watch-${a}"></i></a>`,r+=`<a href="https://github.com/inviro/${n}/stargazers" aria-label = "${n} Stargazers"><i class="fa fa-lg fa-star" id="star-${a}"></i></a>`,r+=`<a href="https://github.com/inviro/${n}/network/members" aria-label = "${n} Forks"><i class="fa fa-lg fa-code-branch" id="fork-${a}"></i></a>`,document.getElementById(`repo-stats-${a}`).innerHTML=r,setRepoStats(n,a)}function loadProjects(){let t=document.getElementsByClassName("project");for(let e=0;e<t.length;e++)loadProject(`project-${e}`)}function setThemeLight(){let t=document.documentElement;t.style.setProperty("--primary-color","3, 4, 94"),t.style.setProperty("--overlay-color","rgba(245, 250, 255, 0.95)"),t.style.setProperty("--header-color","33, 158, 188"),t.style.setProperty("--highlight-color","rgba(255, 255, 255, .90)")}function setThemeDark(){let t=document.documentElement;t.style.setProperty("--primary-color","255, 255, 255"),t.style.setProperty("--overlay-color","rgba(50, 50, 140, .5)"),t.style.setProperty("--header-color","3, 4, 94"),t.style.setProperty("--highlight-color","#219EBC")}function addThemePicker(){document.getElementById("theme-light").checked=!0,document.getElementById("color-theme").style.display="inline",document.getElementById("theme-light").onclick=setThemeLight,document.getElementById("theme-dark").onclick=setThemeDark}function addAnimations(){let t=document.getElementsByClassName("logo")[0];t.addEventListener("mouseover",()=>{t.style.animation="rotation 2s infinite linear"}),t.addEventListener("mouseout",()=>{t.style.animation="none"})}function addTextAnimation(t,e){if(e.indexOf(" | ")>-1){let n=!1,a=e.split(" | "),r=0;setInterval(()=>{n||(t.innerHTML=a[r],r=(r+1)%a.length)},4500),t.addEventListener("mouseover",()=>{n=!0}),t.addEventListener("mouseout",()=>{n=!1})}}function updateHitCount(){let t=document.getElementById("visits-display");fetch(atob("aHR0cHM6Ly91cy1jZW50cmFsMS1hYnJhaGFtY2hlbndlYi5jbG91ZGZ1bmN0aW9ucy5uZXQvd2Vic2l0ZUhpdHMg")).then(t=>t.json()).then(e=>{let n=`<p class="noselect"><strong>Weekly visits:  </strong>${parseInt(e.weeklyHits,10).toLocaleString()}`;n+=`<br><strong>Total visits:  </strong>${parseInt(e.totalHits,10).toLocaleString()}</p>`,t.innerHTML=n})}let canvas,ctx,particles=[],cursorX=-9999,cursorY=-9999;function initParticles(){ctx=(canvas=document.getElementById("particle-canvas")).getContext("2d"),canvas.width=window.innerWidth,canvas.height=window.innerHeight;for(let t=0;t<100;t++)particles.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-.5)*2,vy:(Math.random()-.5)*2,size:10*Math.random()+1,color:`rgba(255, 255, 255, ${Math.random()})`});window.addEventListener("resize",()=>{canvas.width=window.innerWidth,canvas.height=window.innerHeight}),window.addEventListener("mousemove",t=>{let e=getMousePos(t,canvas);cursorX=e.x,cursorY=e.y}),window.addEventListener("mousedown",t=>{let e=getMousePos(t,canvas);for(let n=0;n<10;n++)particles.push({x:e.x,y:e.y,vx:(Math.random()-.5)*4,vy:(Math.random()-.5)*4,size:10*Math.random()+1,color:`rgba(255, 255, 255, ${Math.random()})`})}),animateParticles()}function getMousePos(t,e){let n=e||t.target,a=n.getBoundingClientRect();return{x:t.clientX-a.left,y:t.clientY-a.top}}function animateParticles(){ctx.clearRect(0,0,canvas.width,canvas.height),particles.forEach(t=>{t.x+=t.vx,t.y+=t.vy,(t.x<0||t.x>canvas.width)&&(t.vx*=-1),(t.y<0||t.y>canvas.height)&&(t.vy*=-1);let e=t.x-cursorX,n=t.y-cursorY,a=Math.sqrt(e*e+n*n);if(a<t.size&&(t.vx*=-1,t.vy*=-1,a>0)){let r=t.size-a+5;t.x+=e/a*r,t.y+=n/a*r}ctx.beginPath(),ctx.arc(t.x,t.y,t.size,0,2*Math.PI),ctx.fillStyle=t.color,ctx.fill()}),requestAnimationFrame(animateParticles)}window.onload=()=>{updateHitCount(),addThemePicker(),addAnimations(),loadProjects(),initParticles()};